def check_inclusion(s1: str, s2: str) -> bool:
    n, m = len(s1), len(s2)
    if n > m:
        return False
    need = Counter(s1)
    window = Counter(s2[:n])
    if window == need:
        return True
    for i in range(n, m):
        window[s2[i]] += 1
        left_char = s2[i - n]
        window[left_char] -= 1
        if window[left_char] == 0:
            del window[left_char]
        if window == need:
            return True
    return False

