def min_window(s: str, t: str) -> str:
    if not t or not s:
        return ''
    need = Counter(t)
    missing = len(t)
    left = 0
    best_len = float('inf')
    best_start = 0
    for right, ch in enumerate(s):
        if need[ch] > 0:
            missing -= 1
        need[ch] -= 1
        while missing == 0:
            if right - left + 1 < best_len:
                best_len = right - left + 1
                best_start = left
            need[s[left]] += 1
            if need[s[left]] > 0:
                missing += 1
            left += 1
    return '' if best_len == float('inf') else s[best_start:best_start + best_len]

