class MinStack:
    def __init__(self) -> None:
        self.stack: list[int] = []
        self.min_stack: list[int] = []

    def push(self, val: int) -> None:
        self.stack.append(val)
        prev_min = self.min_stack[-1] if self.min_stack else val
        self.min_stack.append(min(val, prev_min))

    def pop(self) -> None:
        self.stack.pop()
        self.min_stack.pop()

