def search_matrix(matrix: list[list[int]], target: int) -> bool:
    n, m = len(matrix), len(matrix[0])
    low, high = 0, n * m - 1
    while low <= high:
        mid = (low + high) // 2
        val = matrix[mid // m][mid % m]
