def min_eating_speed(piles: list[int], h: int) -> int:
    low, high = 1, max(piles)
    while low < high:
        mid = (low + high) // 2
        hours = sum(math.ceil(pile / mid) for pile in piles)
        if hours <= h:
            high = mid
        else:
            low = mid + 1
    return low

