def max_path_sum(root: TreeNode | None) -> int:
    result = float('-inf')

    def dfs(node: TreeNode | None) -> int:
        nonlocal result
        if not node:
            return 0
        left = max(dfs(node.left), 0)
        right = max(dfs(node.right), 0)
        result = max(result, node.val + left + right)
        return node.val + max(left, right)

    dfs(root)
    return int(result)

