            return False
        temp = board[i][j]
        board[i][j] = '#'
        found = (dfs(i + 1, j, k + 1) or dfs(i - 1, j, k + 1) or
                 dfs(i, j + 1, k + 1) or dfs(i, j - 1, k + 1))
        board[i][j] = temp
        return found

    for i in range(n):
