        '6': 'mno', '7': 'pqrs', '8': 'tuv', '9': 'wxyz',
    }
    result: list[str] = []
    current: list[str] = []

    def backtrack(index: int) -> None:
        if index == len(digits):
            result.append(''.join(current))
            return
        for ch in mapping[digits[index]]:
            current.append(ch)
            backtrack(index + 1)
            current.pop()

    backtrack(0)
    return result

