    pacific, atlantic = set(), set()

    def dfs(i: int, j: int, visited: set, prev_height: int) -> None:
        if (i < 0 or i >= n or j < 0 or j >= m or
                (i, j) in visited or heights[i][j] < prev_height):
            return
        visited.add((i, j))
        for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            dfs(i + di, j + dj, visited, heights[i][j])

    for j in range(m):
        dfs(0, j, pacific, heights[0][j])
        dfs(n - 1, j, atlantic, heights[n - 1][j])
    for i in range(n):
        dfs(i, 0, pacific, heights[i][0])
        dfs(i, m - 1, atlantic, heights[i][m - 1])

    return [[i, j] for i in range(n) for j in range(m) if (i, j) in pacific and (i, j) in atlantic]

